module top_module(
    X    ,
    A    ,
    SLEEP
);// Module ports
    output X    ;
    input  A    ;
    input  SLEEP;

    // Module supplies
    supply1 KAPWR;
    supply0 VGND ;
    supply1 VPB  ;
    supply0 VNB  ;

    // Local signals
    wire actv;

    //  Name  Output  Other arguments
    not not0 (actv, SLEEP          );
    and and0 (X     , A, actv      );

endmodule
